"use client";

import { useRef, useEffect, useState, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Send, ArrowLeft, MoreVertical, Image as ImageIcon } from "lucide-react";
import { useChat } from "@/hooks/use-chat";
import { MessageBubble, TypingIndicator, DateDivider } from "./message-bubble";
import type { Conversation } from "@/types";

function shouldShowDateDivider(prev: string | undefined, curr: string): boolean {
  if (!prev) return true;
  return new Date(prev).toDateString() !== new Date(curr).toDateString();
}

interface ChatWindowProps {
  conversation: Conversation;
  onBack?: () => void;
}

export function ChatWindow({ conversation, onBack }: ChatWindowProps) {
  const { messages, isTyping, sendMessage, sendTyping, currentUserId } = useChat(conversation.id);
  const [draft, setDraft] = useState("");
  const bottomRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Scroll to bottom on new messages
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages.length, isTyping]);

  const handleSend = useCallback(async () => {
    const content = draft.trim();
    if (!content) return;
    setDraft("");
    sendTyping(false);
    await sendMessage(content);
  }, [draft, sendMessage, sendTyping]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setDraft(e.target.value);
    sendTyping(e.target.value.length > 0);
    // Auto-resize
    e.target.style.height = "auto";
    e.target.style.height = `${Math.min(e.target.scrollHeight, 120)}px`;
  };

  const other = conversation.other_user;

  return (
    <div className="flex flex-col h-full bg-[var(--color-void)]">
      {/* Header */}
      <div className="flex items-center gap-3 px-4 py-3 border-b border-[var(--color-border)] bg-[var(--color-surface)] shrink-0">
        {onBack && (
          <button
            onClick={onBack}
            className="text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] transition-colors p-1 -ml-1 rounded"
          >
            <ArrowLeft className="h-5 w-5" />
          </button>
        )}

        <div className="w-9 h-9 rounded-full bg-amber-500/20 border border-amber-500/30 flex items-center justify-center shrink-0">
          <span className="font-display text-sm text-amber-400">
            {other.full_name.charAt(0).toUpperCase()}
          </span>
        </div>

        <div className="flex-1 min-w-0">
          <p className="font-medium text-sm text-[var(--color-text-primary)] truncate">{other.full_name}</p>
          <p className="text-xs text-[var(--color-text-muted)] truncate">{conversation.listing_title}</p>
        </div>

        <button className="text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] transition-colors p-1.5 rounded">
          <MoreVertical className="h-4 w-4" />
        </button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto px-4 py-4 space-y-1 scroll-smooth">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center py-12">
            <div className="w-16 h-16 rounded-full bg-amber-500/10 border border-amber-500/20 flex items-center justify-center mb-4">
              <ImageIcon className="h-7 w-7 text-amber-400/50" />
            </div>
            <p className="text-[var(--color-text-secondary)] text-sm">No messages yet</p>
            <p className="text-[var(--color-text-muted)] text-xs mt-1">
              Start the conversation about {conversation.listing_title}
            </p>
          </div>
        )}

        {messages.map((msg, i) => {
          const prev = messages[i - 1];
          const showDivider = shouldShowDateDivider(prev?.created_at, msg.created_at);
          const isMine = msg.sender_id === currentUserId;

          return (
            <div key={msg.id}>
              {showDivider && <DateDivider date={msg.created_at} />}
              <MessageBubble message={msg} isMine={isMine} />
            </div>
          );
        })}

        <AnimatePresence>
          {isTyping && (
            <motion.div key="typing">
              <TypingIndicator />
            </motion.div>
          )}
        </AnimatePresence>

        <div ref={bottomRef} />
      </div>

      {/* Input bar */}
      <div className="shrink-0 border-t border-[var(--color-border)] bg-[var(--color-surface)] px-4 py-3">
        <div className="flex items-end gap-3">
          <textarea
            ref={textareaRef}
            value={draft}
            onChange={handleChange}
            onKeyDown={handleKeyDown}
            placeholder="Message…"
            rows={1}
            className="flex-1 resize-none bg-[var(--color-void)] border border-[var(--color-border)] rounded-2xl px-4 py-2.5 text-sm text-[var(--color-text-primary)] placeholder:text-[var(--color-text-muted)] focus:outline-none focus:border-amber-500/50 transition-colors leading-relaxed max-h-[120px] overflow-y-auto"
          />
          <motion.button
            onClick={handleSend}
            disabled={!draft.trim()}
            whileTap={{ scale: 0.92 }}
            className="shrink-0 w-10 h-10 rounded-full flex items-center justify-center transition-all disabled:opacity-30 disabled:cursor-not-allowed bg-amber-500 hover:bg-amber-400 text-black"
          >
            <Send className="h-4 w-4" />
          </motion.button>
        </div>
        <p className="text-[10px] text-[var(--color-text-muted)] mt-2 text-center">
          Messages are end-to-end encrypted
        </p>
      </div>
    </div>
  );
}
