"use client";

import { motion } from "framer-motion";
import { formatDistanceToNow } from "date-fns";
import { MessageCircle } from "lucide-react";
import type { Conversation } from "@/types";

interface ChatListProps {
  conversations: Conversation[];
  activeId?: string;
  onSelect: (conversation: Conversation) => void;
}

export function ChatList({ conversations, activeId, onSelect }: ChatListProps) {
  if (conversations.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full py-16 text-center px-6">
        <div className="w-14 h-14 rounded-full bg-amber-500/10 border border-amber-500/20 flex items-center justify-center mb-4">
          <MessageCircle className="h-6 w-6 text-amber-400/50" />
        </div>
        <p className="text-[var(--color-text-secondary)] text-sm font-medium">No conversations yet</p>
        <p className="text-[var(--color-text-muted)] text-xs mt-1">
          Contact a seller from a listing to start chatting
        </p>
      </div>
    );
  }

  return (
    <ul className="divide-y divide-[var(--color-border)]">
      {conversations.map((conv, i) => (
        <motion.li
          key={conv.id}
          initial={{ opacity: 0, x: -10 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: i * 0.04 }}
        >
          <button
            onClick={() => onSelect(conv)}
            className={`w-full flex items-start gap-3 px-4 py-4 hover:bg-[var(--color-surface-raised)] transition-colors text-left ${
              activeId === conv.id ? "bg-amber-500/5 border-l-2 border-amber-500" : ""
            }`}
          >
            {/* Avatar */}
            <div className="relative shrink-0">
              <div className="w-11 h-11 rounded-full bg-[var(--color-surface-raised)] border border-[var(--color-border)] flex items-center justify-center">
                <span className="font-display text-base text-[var(--color-text-primary)]">
                  {conv.other_user.full_name.charAt(0).toUpperCase()}
                </span>
              </div>
              {conv.unread_count > 0 && (
                <span className="absolute -top-0.5 -right-0.5 w-5 h-5 rounded-full bg-amber-500 text-black text-[10px] font-bold flex items-center justify-center">
                  {conv.unread_count > 9 ? "9+" : conv.unread_count}
                </span>
              )}
            </div>

            {/* Content */}
            <div className="flex-1 min-w-0">
              <div className="flex items-baseline justify-between gap-2">
                <span className={`text-sm font-medium truncate ${
                  conv.unread_count > 0
                    ? "text-[var(--color-text-primary)]"
                    : "text-[var(--color-text-secondary)]"
                }`}>
                  {conv.other_user.full_name}
                </span>
                <span className="text-[10px] text-[var(--color-text-muted)] shrink-0">
                  {formatDistanceToNow(new Date(conv.updated_at), { addSuffix: false })}
                </span>
              </div>
              <p className="text-xs text-amber-400/80 truncate mt-0.5">{conv.listing_title}</p>
              {conv.last_message && (
                <p className={`text-xs truncate mt-0.5 ${
                  conv.unread_count > 0
                    ? "text-[var(--color-text-primary)] font-medium"
                    : "text-[var(--color-text-muted)]"
                }`}>
                  {conv.last_message.content}
                </p>
              )}
            </div>
          </button>
        </motion.li>
      ))}
    </ul>
  );
}
