"use client";

import { useEffect, useState } from "react";
import { useSearchParams } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import { motion, AnimatePresence } from "framer-motion";
import { MessageCircle } from "lucide-react";
import { chatService } from "@/services/chat.service";
import { useChatStore } from "@/store/chat.store";
import { ChatList } from "@/features/chat/chat-list";
import { ChatWindow } from "@/features/chat/chat-window";
import type { Conversation } from "@/types";

export default function ChatPage() {
  const searchParams = useSearchParams();
  const initialId = searchParams.get("id");
  const { conversations, setConversations, activeConversationId, setActiveConversation } = useChatStore();
  const [selectedConv, setSelectedConv] = useState<Conversation | null>(null);

  const { isLoading } = useQuery({
    queryKey: ["conversations"],
    queryFn: async () => {
      const data = await chatService.getConversations();
      setConversations(data);
      return data;
    },
    refetchInterval: 30000,
  });

  // Auto-select conversation from URL
  useEffect(() => {
    if (initialId && conversations.length > 0) {
      const found = conversations.find((c) => c.id === initialId);
      if (found) {
        setSelectedConv(found);
        setActiveConversation(found.id);
      }
    }
  }, [initialId, conversations, setActiveConversation]);

  const handleSelect = (conv: Conversation) => {
    setSelectedConv(conv);
    setActiveConversation(conv.id);
  };

  const handleBack = () => {
    setSelectedConv(null);
    setActiveConversation(null);
  };

  return (
    <div className="flex h-[calc(100dvh-8rem)] rounded-[var(--radius-lg)] border border-[var(--color-border)] overflow-hidden bg-[var(--color-surface)]">
      {/* Sidebar */}
      <div className={`flex-shrink-0 w-full sm:w-72 md:w-80 border-r border-[var(--color-border)] flex flex-col ${
        selectedConv ? "hidden sm:flex" : "flex"
      }`}>
        {/* Header */}
        <div className="flex items-center gap-3 px-4 py-4 border-b border-[var(--color-border)] shrink-0">
          <MessageCircle className="h-5 w-5 text-amber-400" />
          <span className="font-display tracking-widest text-sm">MESSAGES</span>
          {conversations.filter((c) => c.unread_count > 0).length > 0 && (
            <span className="ml-auto px-2 py-0.5 rounded-full bg-amber-500/20 text-amber-400 text-xs font-medium">
              {conversations.reduce((acc, c) => acc + c.unread_count, 0)}
            </span>
          )}
        </div>

        {/* List */}
        <div className="flex-1 overflow-y-auto">
          {isLoading ? (
            <div className="p-4 space-y-3">
              {Array.from({ length: 4 }).map((_, i) => (
                <div key={i} className="flex gap-3 animate-pulse">
                  <div className="skeleton w-11 h-11 rounded-full" />
                  <div className="flex-1 space-y-2">
                    <div className="skeleton h-3 w-3/4 rounded" />
                    <div className="skeleton h-3 w-1/2 rounded" />
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <ChatList
              conversations={conversations}
              activeId={selectedConv?.id}
              onSelect={handleSelect}
            />
          )}
        </div>
      </div>

      {/* Chat area */}
      <div className={`flex-1 min-w-0 ${!selectedConv ? "hidden sm:flex" : "flex"} flex-col`}>
        {selectedConv ? (
          <ChatWindow conversation={selectedConv} onBack={handleBack} />
        ) : (
          <div className="flex flex-col items-center justify-center h-full text-center p-8">
            <div className="w-20 h-20 rounded-full bg-amber-500/10 border border-amber-500/20 flex items-center justify-center mb-5">
              <MessageCircle className="h-9 w-9 text-amber-400/60" />
            </div>
            <h3 className="font-display text-2xl tracking-wide mb-2">YOUR MESSAGES</h3>
            <p className="text-sm text-[var(--color-text-muted)] max-w-xs">
              Select a conversation to start chatting, or contact a seller from any listing.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}
