"use client";

import { motion } from "framer-motion";
import { Check, CheckCheck, Clock, AlertTriangle } from "lucide-react";
import { formatTime } from "@/lib/utils";
import type { ChatMessage, MessageStatus } from "@/types";

function StatusIcon({ status }: { status: MessageStatus }) {
  if (status === "sending") return <Clock className="h-3 w-3 text-[var(--color-text-muted)]" />;
  if (status === "sent") return <Check className="h-3 w-3 text-[var(--color-text-muted)]" />;
  if (status === "delivered") return <CheckCheck className="h-3 w-3 text-[var(--color-text-muted)]" />;
  return <CheckCheck className="h-3 w-3 text-amber-400" />;
}

interface MessageBubbleProps {
  message: ChatMessage;
  isMine: boolean;
  showTime?: boolean;
}

export function MessageBubble({ message, isMine, showTime }: MessageBubbleProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 8, scale: 0.97 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      transition={{ duration: 0.2, ease: "easeOut" }}
      className={`flex flex-col ${isMine ? "items-end" : "items-start"} gap-0.5`}
    >
      {/* Safety warning */}
      {message.is_flagged && message.safety_warnings && message.safety_warnings.length > 0 && (
        <div className="flex items-start gap-2 px-3 py-2 rounded-[var(--radius-md)] bg-red-500/10 border border-red-500/20 max-w-xs mb-1">
          <AlertTriangle className="h-3.5 w-3.5 text-red-400 mt-0.5 shrink-0" />
          <div>
            {message.safety_warnings.map((w, i) => (
              <p key={i} className="text-xs text-red-400">{w}</p>
            ))}
          </div>
        </div>
      )}

      <div
        className={`max-w-xs sm:max-w-sm lg:max-w-md px-4 py-2.5 rounded-2xl ${
          isMine
            ? "rounded-br-sm bg-amber-500 text-black"
            : "rounded-bl-sm bg-[var(--color-surface-raised)] text-[var(--color-text-primary)] border border-[var(--color-border)]"
        }`}
      >
        <p className="text-sm leading-relaxed break-words">{message.content}</p>
      </div>

      <div className={`flex items-center gap-1.5 px-1 ${isMine ? "flex-row-reverse" : "flex-row"}`}>
        <span className="text-[10px] text-[var(--color-text-muted)]">
          {formatTime(message.created_at)}
        </span>
        {isMine && <StatusIcon status={message.status} />}
      </div>
    </motion.div>
  );
}

export function TypingIndicator() {
  return (
    <motion.div
      initial={{ opacity: 0, y: 4 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: 4 }}
      className="flex items-start"
    >
      <div className="px-4 py-3 rounded-2xl rounded-bl-sm bg-[var(--color-surface-raised)] border border-[var(--color-border)]">
        <div className="flex items-center gap-1">
          <span className="typing-dot" />
          <span className="typing-dot" style={{ animationDelay: "0.2s" }} />
          <span className="typing-dot" style={{ animationDelay: "0.4s" }} />
        </div>
      </div>
    </motion.div>
  );
}

export function DateDivider({ date }: { date: string }) {
  const label = (() => {
    const d = new Date(date);
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(today.getDate() - 1);
    if (d.toDateString() === today.toDateString()) return "Today";
    if (d.toDateString() === yesterday.toDateString()) return "Yesterday";
    return d.toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" });
  })();

  return (
    <div className="flex items-center gap-3 my-4">
      <div className="flex-1 h-px bg-[var(--color-border)]" />
      <span className="text-xs text-[var(--color-text-muted)] px-2">{label}</span>
      <div className="flex-1 h-px bg-[var(--color-border)]" />
    </div>
  );
}
